using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "Application Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetSettings()
    {
        var config = new
        {
            AppName = "ConfigMcpServer",
            Version = "1.0.0",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/environment",
        Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironment()
    {
        var env = new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessorCount = Environment.ProcessorCount
        };

        return JsonSerializer.Serialize(env, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Checks whether a specific feature flag is enabled.")]
    public static string CheckFeatureFlag(
        [Description("The name of the feature flag to check (e.g., 'DarkMode', 'BetaAccess')")] string flagName)
    {
        var flags = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
        {
            ["DarkMode"] = true,
            ["BetaAccess"] = false,
            ["Notifications"] = true
        };

        if (flags.TryGetValue(flagName, out var enabled))
            return $"Feature '{flagName}' is {(enabled ? "enabled" : "disabled")}.";

        return $"Feature '{flagName}' not found. Available: {string.Join(", ", flags.Keys)}";
    }

    [McpServerTool, Description("Updates the timeout setting and returns the new value.")]
    public static string SetTimeout(
        [Description("New timeout value in seconds (1-300)")] int seconds)
    {
        if (seconds < 1 || seconds > 300)
            return "Error: timeout must be between 1 and 300 seconds.";

        return $"Timeout updated to {seconds} seconds.";
    }
}

